g? // Developer who initiated the run\n\n  // Configuration snapshot\n  config Json? // Store the exact configuration used\n\n  // Relationships\n  topicAssignments TopicAssignment[]\n  clusterResults   ClusterResult[]\n\n  @@index([status])\n  @@index([startedAt])\n  @@map(\"analysis_runs\")\n}\n\n// System configuration and settings\nmodel SystemConfig {\n  id        String     @id @default(cuid())\n  key       String     @unique\n  value     String     @db.Text\n  type      ConfigType @default(STRING)\n  updatedAt DateTime   @updatedAt @map(\"updated_at\")\n  updatedBy String?    @map(\"updated_by\")\n\n  @@map(\"system_config\")\n}\n\n// User sessions for tracking and analytics\nmodel UserSession {\n  id           String   @id @default(cuid())\n  sessionId    String   @unique @map(\"session_id\")\n  userId       String?  @map(\"user_id\")\n  isDevSession Boolean  @default(false) @map(\"is_dev_session\")\n  ipAddress    String?  @map(\"ip_address\")\n  userAgent    String?  @map(\"user_agent\")\n  country      String?\n  region       String?\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n  lastActivity DateTime @default(now()) @map(\"last_activity\")\n\n  @@index([sessionId])\n  @@index([isDevSession])\n  @@index([createdAt])\n  @@map(\"user_sessions\")\n}\n\n// Data sync tracking for Google Sheets\nmodel DataSync {\n  id               String     @id @default(cuid())\n  source           String // \"questions_sheet\", \"topics_sheet\"\n  sourceUrl        String? // Google Sheets URL\n  lastSyncAt       DateTime   @map(\"last_sync_at\")\n  status           SyncStatus @default(PENDING)\n  recordsProcessed Int?       @map(\"records_processed\")\n  recordsAdded     Int?       @map(\"records_added\")\n  recordsUpdated   Int?       @map(\"records_updated\")\n  errorMessage     String?    @map(\"error_message\") @db.Text\n\n  @@index([source])\n  @@index([lastSyncAt])\n  @@map(\"data_syncs\")\n}\n\n// Enums\nenum AssignmentType {\n  SIMILARITY_MATCH // As